import { olka, createSignal, createEffect } from "../core";
export default () => {
    let [text, setText] = createSignal("");
    return (
        createEffect(() => {
            console.log("Text:", text());
        }),
        olka.createElement(
            "div",
            null,
            olka.createElement("h1", null, text),
            olka.createElement("input", {
                type: "text",
                onInput: (e) => setText(e.target.value),
            })
        )
    );
};
